import type { ComponentProps } from 'react';
import { ContextMenu as ContextMenuPrimitive } from '@base-ui/react/context-menu';
import { clsx } from 'clsx';
import { CheckIcon, ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './ContextMenu.module.css';

export type ContextMenuPositionerProps = Pick<
  ContextMenuPrimitive.Positioner.Props,
  | 'side'
  | 'sideOffset'
  | 'align'
  | 'alignOffset'
  | 'collisionAvoidance'
  | 'collisionBoundary'
  | 'collisionPadding'
>;

export type ContextMenuContentProps = ContextMenuPrimitive.Popup.Props & ContextMenuPositionerProps;

const CONTEXT_MENU_CONTENT_SIDE_OFFSET = 8;
const ContextMenu = ContextMenuPrimitive.Root;
const ContextMenuSubmenu = ContextMenuPrimitive.SubmenuRoot;
export type ContextMenuIndicatorPosition = 'start' | 'end' | 'none';
export type ContextMenuRadioItemProps = ContextMenuPrimitive.RadioItem.Props & {
  indicator?: ContextMenuIndicatorPosition;
};
export type ContextMenuCheckboxItemProps = ContextMenuPrimitive.CheckboxItem.Props & {
  indicator?: ContextMenuIndicatorPosition;
};

function ContextMenuTrigger({ className, render, ...props }: ContextMenuPrimitive.Trigger.Props) {
  const triggerClassName = render ? className : mergeClassName(className, styles.trigger);

  return (
    <ContextMenuPrimitive.Trigger
      data-slot="context-menu-trigger"
      render={render}
      className={triggerClassName}
      {...props}
    />
  );
}

function ContextMenuPortal(props: ContextMenuPrimitive.Portal.Props) {
  return <ContextMenuPrimitive.Portal data-slot="context-menu-portal" {...props} />;
}

function ContextMenuBackdrop({ className, ...props }: ContextMenuPrimitive.Backdrop.Props) {
  return (
    <ContextMenuPrimitive.Backdrop
      data-slot="context-menu-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function ContextMenuPositioner({ className, ...props }: ContextMenuPrimitive.Positioner.Props) {
  return (
    <ContextMenuPrimitive.Positioner
      data-slot="context-menu-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function ContextMenuPopup({ className, ...props }: ContextMenuPrimitive.Popup.Props) {
  return (
    <ContextMenuPrimitive.Popup
      data-slot="context-menu-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function ContextMenuContent({
  className,
  children,
  sideOffset = CONTEXT_MENU_CONTENT_SIDE_OFFSET,
  side,
  align,
  alignOffset,
  collisionAvoidance,
  collisionBoundary,
  collisionPadding,
  ...props
}: ContextMenuContentProps) {
  return (
    <ContextMenuPortal>
      <ContextMenuPositioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        collisionAvoidance={collisionAvoidance}
        collisionBoundary={collisionBoundary}
        collisionPadding={collisionPadding}
      >
        <ContextMenuPopup className={className} {...props}>
          {children}
        </ContextMenuPopup>
      </ContextMenuPositioner>
    </ContextMenuPortal>
  );
}

function ContextMenuSubmenuContent({
  sideOffset = getSubmenuOffset,
  alignOffset = getSubmenuOffset,
  ...props
}: ContextMenuContentProps) {
  return <ContextMenuContent sideOffset={sideOffset} alignOffset={alignOffset} {...props} />;
}

function ContextMenuItem({ className, ...props }: ContextMenuPrimitive.Item.Props) {
  return (
    <ContextMenuPrimitive.Item
      data-slot="context-menu-item"
      className={mergeClassName(className, styles.item)}
      {...props}
    />
  );
}

function ContextMenuLinkItem({ className, ...props }: ContextMenuPrimitive.LinkItem.Props) {
  return (
    <ContextMenuPrimitive.LinkItem
      data-slot="context-menu-link-item"
      className={mergeClassName(className, styles.linkItem)}
      {...props}
    />
  );
}

function ContextMenuSeparator({ className, ...props }: ContextMenuPrimitive.Separator.Props) {
  return (
    <ContextMenuPrimitive.Separator
      data-slot="context-menu-separator"
      className={mergeClassName(className, styles.separator)}
      {...props}
    />
  );
}

function ContextMenuGroup({ className, ...props }: ContextMenuPrimitive.Group.Props) {
  return (
    <ContextMenuPrimitive.Group
      data-slot="context-menu-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
}

function ContextMenuGroupLabel({ className, ...props }: ContextMenuPrimitive.GroupLabel.Props) {
  return (
    <ContextMenuPrimitive.GroupLabel
      data-slot="context-menu-group-label"
      className={mergeClassName(className, styles.groupLabel)}
      {...props}
    />
  );
}

function ContextMenuSubmenuTrigger({
  className,
  ...props
}: ContextMenuPrimitive.SubmenuTrigger.Props) {
  return (
    <ContextMenuPrimitive.SubmenuTrigger
      data-slot="context-menu-submenu-trigger"
      className={mergeClassName(className, styles.submenuTrigger)}
      {...props}
    />
  );
}

function ContextMenuSubmenuTriggerIcon({ className, children, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="context-menu-submenu-trigger-icon"
      className={clsx(styles.submenuTriggerIcon, className)}
      {...props}
    >
      {children ?? <ChevronRightIcon className={styles.iconSvg} />}
    </span>
  );
}

function ContextMenuRadioGroup({ className, ...props }: ContextMenuPrimitive.RadioGroup.Props) {
  return (
    <ContextMenuPrimitive.RadioGroup
      data-slot="context-menu-radio-group"
      className={mergeClassName(className, styles.radioGroup)}
      {...props}
    />
  );
}

function ContextMenuRadioItem({ className, indicator, ...props }: ContextMenuRadioItemProps) {
  return (
    <ContextMenuPrimitive.RadioItem
      data-slot="context-menu-radio-item"
      data-indicator-position={indicator}
      className={mergeClassName(className, styles.radioItem)}
      {...props}
    />
  );
}

function ContextMenuRadioItemIndicator({
  className,
  children,
  ...props
}: ContextMenuPrimitive.RadioItemIndicator.Props) {
  return (
    <ContextMenuPrimitive.RadioItemIndicator
      data-slot="context-menu-radio-item-indicator"
      className={mergeClassName(className, styles.radioItemIndicator)}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </ContextMenuPrimitive.RadioItemIndicator>
  );
}

function ContextMenuCheckboxItem({ className, indicator, ...props }: ContextMenuCheckboxItemProps) {
  return (
    <ContextMenuPrimitive.CheckboxItem
      data-slot="context-menu-checkbox-item"
      data-indicator-position={indicator}
      className={mergeClassName(className, styles.checkboxItem)}
      {...props}
    />
  );
}

function ContextMenuCheckboxItemIndicator({
  className,
  children,
  ...props
}: ContextMenuPrimitive.CheckboxItemIndicator.Props) {
  return (
    <ContextMenuPrimitive.CheckboxItemIndicator
      data-slot="context-menu-checkbox-item-indicator"
      className={mergeClassName(className, styles.checkboxItemIndicator)}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </ContextMenuPrimitive.CheckboxItemIndicator>
  );
}

function ContextMenuItemText({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="context-menu-item-text"
      className={clsx(styles.itemText, className)}
      {...props}
    />
  );
}

function ContextMenuItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="context-menu-item-text-content"
      className={clsx(styles.itemTextContent, className)}
      {...props}
    />
  );
}

function ContextMenuItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="context-menu-item-text-icon"
      className={clsx(styles.itemTextIcon, className)}
      {...props}
    />
  );
}

function ContextMenuItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="context-menu-item-text-label"
      className={clsx(styles.itemTextLabel, className)}
      {...props}
    />
  );
}

function ContextMenuItemShortcut({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="context-menu-item-shortcut"
      className={clsx(styles.itemShortcut, className)}
      {...props}
    />
  );
}

function getSubmenuOffset({ side }: { side: ContextMenuPrimitive.Positioner.Props['side'] }) {
  return side === 'top' || side === 'bottom' ? 4 : -4;
}

export {
  ContextMenu,
  ContextMenuSubmenu,
  ContextMenuTrigger,
  ContextMenuPortal,
  ContextMenuBackdrop,
  ContextMenuPositioner,
  ContextMenuPopup,
  ContextMenuContent,
  ContextMenuSubmenuContent,
  ContextMenuItem,
  ContextMenuLinkItem,
  ContextMenuSeparator,
  ContextMenuGroup,
  ContextMenuGroupLabel,
  ContextMenuSubmenuTrigger,
  ContextMenuSubmenuTriggerIcon,
  ContextMenuRadioGroup,
  ContextMenuRadioItem,
  ContextMenuRadioItemIndicator,
  ContextMenuCheckboxItem,
  ContextMenuCheckboxItemIndicator,
  ContextMenuItemText,
  ContextMenuItemTextContent,
  ContextMenuItemTextIcon,
  ContextMenuItemTextLabel,
  ContextMenuItemShortcut,
};

@layer ui.components {
  .trigger {
    box-sizing: border-box;
    margin: 0;
    outline: 0;

    &:focus-visible {
      outline: var(--border-width-sm) solid var(--context-menu-focus-ring-color, var(--color-ring));
      outline-offset: 0;
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--context-menu-disabled-opacity, var(--opacity-disabled));
    }
  }

  .iconSvg {
    width: 100%;
    height: 100%;
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--context-menu-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--context-menu-backdrop-blur, 4px)));
    transition:
      opacity
        var(
          --context-menu-backdrop-transition,
          var(--context-menu-transition, var(--transition-default))
        ),
      backdrop-filter
        var(
          --context-menu-backdrop-transition,
          var(--context-menu-transition, var(--transition-default))
        );

    &[data-starting-style] {
      opacity: var(--context-menu-backdrop-starting-opacity, 0);
      backdrop-filter: var(--context-menu-backdrop-starting-blur, none);
    }

    &[data-ending-style] {
      opacity: var(--context-menu-backdrop-ending-opacity, 0);
      backdrop-filter: var(--context-menu-backdrop-ending-blur, none);
    }
  }

  .positioner {
    z-index: var(--z-popup);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    min-width: min(var(--context-menu-popup-min-width, 12rem), var(--available-width, 100vw));
    max-width: min(var(--context-menu-popup-max-width, 20rem), var(--available-width, 100vw));
    max-height: min(var(--context-menu-popup-max-height, 24rem), var(--available-height, 100dvh));
    overflow-y: auto;
    overscroll-behavior: contain;
    outline: 0;
    padding-block: var(--context-menu-popup-padding-y, 0.25rem);
    border: var(--border-width-sm) solid var(--context-menu-popup-border-color, var(--color-border));
    border-radius: var(--context-menu-popup-radius, var(--radius-md));
    background-color: var(--context-menu-popup-bg, var(--color-popover));
    color: var(--context-menu-popup-color, var(--color-popover-foreground));
    box-shadow: var(--context-menu-popup-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      transform var(--context-menu-transition, var(--transition-default)),
      opacity var(--context-menu-transition, var(--transition-default)),
      translate var(--context-menu-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--context-menu-popup-starting-opacity, 0);
      translate: var(--context-menu-popup-starting-translate-x, 0)
        var(--context-menu-popup-starting-translate-y, 0);
      transform: scale(var(--context-menu-popup-starting-scale, var(--scale-popup)));
    }

    &[data-ending-style] {
      opacity: var(--context-menu-popup-ending-opacity, 0);
      translate: var(--context-menu-popup-ending-translate-x, 0)
        var(--context-menu-popup-ending-translate-y, 0);
      transform: scale(var(--context-menu-popup-ending-scale, var(--scale-popup)));
    }
  }

  .item,
  .linkItem,
  .submenuTrigger,
  .radioItem,
  .checkboxItem {
    position: relative;
    box-sizing: border-box;
    min-height: var(--context-menu-item-height, var(--popup-item-min-height, 2rem));
    margin: 0;
    border: 0;
    outline: 0;
    background: var(--context-menu-item-bg, transparent);
    color: inherit;
    font: inherit;
    font-size: var(--context-menu-item-font-size, var(--popup-item-font-size, var(--text-sm)));
    line-height: var(
      --context-menu-item-line-height,
      var(--popup-item-line-height, var(--line-height-text-sm))
    );
    text-decoration: none;
    user-select: none;
    cursor: default;

    &[data-highlighted] {
      z-index: 0;
      color: var(--context-menu-highlight-color, var(--color-background));
    }

    &[data-popup-open] {
      z-index: 0;
    }

    &[data-highlighted]::before,
    &[data-popup-open]::before {
      content: '';
      z-index: -1;
      position: absolute;
      inset-block: 0;
      inset-inline: var(
        --context-menu-highlight-inset-x,
        var(--popup-highlight-inset-x, var(--spacing-1))
      );
      border-radius: var(
        --context-menu-highlight-radius,
        var(--popup-highlight-radius, var(--radius-sm))
      );
    }

    &[data-highlighted]::before {
      background-color: var(--context-menu-highlight-bg, var(--color-foreground));
    }

    &[data-popup-open]::before {
      background-color: var(--context-menu-submenu-open-bg, var(--color-accent));
    }

    &[data-highlighted][data-popup-open]::before {
      background-color: var(--context-menu-highlight-bg, var(--color-foreground));
    }

    &[data-disabled] {
      color: var(--context-menu-item-disabled-color, var(--color-muted-foreground));
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      cursor: default;
    }
  }

  .item,
  .linkItem {
    display: flex;
    align-items: center;
    gap: var(--context-menu-item-gap, var(--spacing-2));
    padding-block: var(--context-menu-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(
        --context-menu-item-padding-x-start,
        var(--popup-item-padding-x-start, 1rem)
      )
      var(--context-menu-item-padding-x-end, var(--popup-item-padding-x-end, 1rem));
  }

  .submenuTrigger {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--context-menu-submenu-trigger-gap, var(--spacing-3));
    padding-block: var(--context-menu-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(
        --context-menu-item-padding-x-start,
        var(--popup-item-padding-x-start, 1rem)
      )
      var(--context-menu-submenu-trigger-padding-x-end, 1rem);
  }

  .submenuTriggerIcon {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--context-menu-submenu-icon-size, 0.875rem);
    height: var(--context-menu-submenu-icon-size, 0.875rem);
    flex-shrink: 0;
    color: currentColor;
  }

  .group {
    display: grid;
    padding-block: var(--context-menu-group-padding-y, 0);
  }

  .groupLabel {
    margin: 0;
    padding-block: var(
      --context-menu-group-label-padding-y,
      var(--popup-group-label-padding-y, 0.35rem)
    );
    padding-inline: var(
        --context-menu-group-label-padding-x-start,
        var(--popup-group-label-padding-x-start, 0.625rem)
      )
      var(--context-menu-group-label-padding-x-end, var(--popup-group-label-padding-x-end, 0.75rem));
    color: var(--context-menu-group-label-color, var(--color-muted-foreground));
    font-size: var(
      --context-menu-group-label-font-size,
      var(--popup-group-label-font-size, var(--text-xs))
    );
    line-height: var(
      --context-menu-group-label-line-height,
      var(--popup-group-label-line-height, var(--line-height-text-xs))
    );
    user-select: none;
    cursor: default;
  }

  .radioGroup {
    display: grid;
  }

  .radioItem,
  .checkboxItem {
    display: grid;
    align-items: center;
    gap: var(--context-menu-check-gap, var(--popup-check-gap, 0.5rem));
    grid-template-columns:
      var(--context-menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem))
      minmax(0, 1fr);
    padding-block: var(--context-menu-item-padding-y, var(--popup-item-padding-y, 0.5rem));
    padding-inline: var(
        --context-menu-check-padding-x-start,
        var(--popup-check-padding-x-start, 0.625rem)
      )
      var(--context-menu-item-padding-x-end, var(--popup-item-padding-x-end, 1rem));

    &[data-indicator-position='none'] {
      grid-template-columns: minmax(0, 1fr);
      padding-inline-start: var(
        --context-menu-item-padding-x-start,
        var(--popup-item-padding-x-start, 1rem)
      );

      & > .radioItemIndicator,
      & > .checkboxItemIndicator {
        display: none;
      }

      & > .itemText {
        grid-column: 1;
      }
    }

    &[data-indicator-position='end'] {
      grid-template-columns:
        minmax(0, 1fr)
        var(--context-menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem));

      & > .radioItemIndicator,
      & > .checkboxItemIndicator {
        grid-column-start: 2;
        justify-self: end;
      }

      & > .itemText {
        grid-column-start: 1;
      }
    }
  }

  .radioItemIndicator,
  .checkboxItemIndicator {
    grid-column: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    box-sizing: border-box;
    flex-shrink: 0;
    width: var(--context-menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem));
    height: var(--context-menu-check-indicator-size, var(--popup-check-indicator-size, 0.75rem));
    padding: var(--context-menu-check-indicator-padding, 0);
    border: var(--context-menu-check-indicator-border-width, var(--border-width-sm)) solid
      var(--context-menu-check-indicator-border-color, transparent);
    border-radius: var(--context-menu-check-indicator-radius, var(--radius-xs));
    background-color: var(--context-menu-check-indicator-bg, transparent);
    color: var(--context-menu-check-indicator-color, currentColor);
  }

  .itemIndicatorIcon {
    width: var(--context-menu-check-icon-size, 100%);
    height: var(--context-menu-check-icon-size, 100%);
  }

  .itemText {
    grid-column: 2;
    min-width: 0;
    overflow: hidden;
  }

  .itemTextContent {
    display: inline-flex;
    align-items: center;
    gap: var(--context-menu-item-text-content-gap, var(--spacing-2));
    max-width: 100%;
    min-width: 0;
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: var(--context-menu-item-text-icon-size, 1rem);
    height: var(--context-menu-item-text-icon-size, 1rem);
    color: var(--context-menu-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemShortcut {
    margin-inline-start: auto;
    padding-inline-start: var(--context-menu-item-shortcut-padding-x-start, var(--spacing-4));
    color: var(--context-menu-item-shortcut-color, var(--color-muted-foreground));
    font-size: var(--context-menu-item-shortcut-font-size, var(--text-xs));
    line-height: var(--context-menu-item-shortcut-line-height, var(--line-height-text-xs));
    white-space: nowrap;
  }

  .separator {
    box-sizing: border-box;
    height: var(--border-width-sm);
    margin-block: var(--context-menu-separator-margin-y, var(--popup-separator-margin-y, 0.375rem));
    margin-inline: var(
        --context-menu-separator-margin-x-start,
        var(--popup-separator-margin-x-start, 1rem)
      )
      var(--context-menu-separator-margin-x-end, var(--popup-separator-margin-x-end, 1rem));
    background-color: var(--context-menu-separator-color, var(--color-border));
  }
}
